Tentu, saya mengerti. Untuk membuat hewan peliharaan digital terlihat "lebih nyata" (hidup) dalam format vektor 2D, kuncinya bukan hanya pada detail gambar, tetapi pada **"Micro-Animations"** (Animasi Mikro) dan **Lingkungan**.

Makhluk hidup tidak pernah diam 100%. Mereka bernapas, berkedip, dan sedikit bergoyang tertiup angin.

Berikut adalah upgrade besar-besaran untuk `PetVisualizer` di `components/Savings.tsx` dengan fitur baru:

1.  **Organic Breathing:** Pet sekarang memiliki animasi "bernapas" (dada naik turun halus).
2.  **Blinking Eyes:** Mata pet akan berkedip secara acak, membuatnya terasa sadar.
3.  **Dynamic Environment:**
    *   **Fase Telur & Bayi:** Ada di dalam **Sarang Jerami** yang detail.
    *   **Fase Dewasa:** Bertengger di **Dahan Pohon** yang kokoh dengan daun yang bergoyang.
4.  **Lighting & Depth:** Menggunakan *Drop Shadows* dan *Gradient Highlights* yang lebih kompleks agar terlihat 3D, tidak gepeng.
5.  **Partikel Emosi:** Saat di-hover atau tumbuh, akan muncul partikel "Love" atau "Musik".

Berikut implementasinya:

# Updated files:

## components/Savings.tsx

```tsx
import React, { useMemo, useEffect, useState } from 'react';
import type { AppState, SavingsGoal } from '../types';
import { PlusCircleIcon, BuildingLibraryIcon, ArrowUturnLeftIcon, SparklesIcon, HeartIcon } from './Icons';

const formatCurrency = (amount: number) => new Intl.NumberFormat('id-ID', { style: 'currency', currency: 'IDR', minimumFractionDigits: 0 }).format(amount);

// --- PLANT VISUALIZATION COMPONENT (UNCHANGED) ---
const PlantVisualizer: React.FC<{
    progress: number; // 0 to 100
    isCompleted: boolean;
    seed: number; // Used to randomize curves slightly
    type: 'finite' | 'infinite';
}> = ({ progress, isCompleted, seed, type }) => {
    // Normalize progress (clamp between 0 and 100)
    const growth = Math.min(100, Math.max(0, progress));

    // Procedural constants based on seed
    const curveDir = seed % 2 === 0 ? 1 : -1; // Curving left or right
    const leafAngleVar = (seed % 20) - 10; 

    // Height of the plant (max 150 units)
    const plantHeight = (growth / 100) * 120;

    // Number of leaves: roughly 1 leaf per 15% progress, max 8-10
    const leafCount = Math.floor(growth / 15);

    const renderLeaves = () => {
        const leaves = [];
        for (let i = 0; i < leafCount; i++) {
            const yPos = 150 - (i * (120 / 8)) - 20; // Distribute leaves up the stem
            const side = i % 2 === 0 ? 1 : -1;
            const scale = 0.5 + (i * 0.05); // Leaves get slightly bigger/smaller logic

            // Leaf SVG path (simple quadratic bezier shape)
            const leafPath = `M0,0 Q${15 * side},${-10} ${30 * side},${-5} Q${15 * side},${10} 0,0`;

            leaves.push(
                <path 
                    key={i}
                    d={leafPath}
                    fill={isCompleted ? "#27AE60" : "#2ECC71"} // Darker green if completed
                    stroke="#1E8449"
                    strokeWidth="1"
                    transform={`translate(100, ${yPos}) rotate(${(-20 * side) + leafAngleVar}) scale(${scale})`}
                    className="animate-fade-in"
                    style={{ animationDelay: `${i * 100}ms` }}
                />
            );
        }
        return leaves;
    };

    return (
        <div className="relative w-full h-52 flex items-end justify-center overflow-hidden rounded-t-xl bg-gradient-to-t from-blue-50 to-white">
            {/* Background Sun/Aura if completed */}
            {isCompleted && (
                <div className="absolute top-4 right-10 w-16 h-16 bg-yellow-200 rounded-full opacity-50 blur-xl animate-pulse"></div>
            )}

            <svg width="200" height="200" viewBox="0 0 200 200" className="z-10">
                {/* Pot */}
                <defs>
                    <linearGradient id="potGradient" x1="0%" y1="0%" x2="100%" y2="0%">
                        <stop offset="0%" stopColor="#8B4513" />
                        <stop offset="50%" stopColor="#A0522D" />
                        <stop offset="100%" stopColor="#8B4513" />
                    </linearGradient>
                </defs>
                <path d="M70 170 L130 170 L120 200 L80 200 Z" fill="url(#potGradient)" stroke="#5D4037" strokeWidth="2" />
                <rect x="65" y="165" width="70" height="10" rx="2" fill="#A0522D" stroke="#5D4037" />

                {/* Seedling Stage (always visible if > 0) */}
                {growth > 0 && (
                    <>
                        {/* Stem */}
                        <path 
                            d={`M100 170 Q${100 + (20 * curveDir)} ${170 - (plantHeight / 2)} 100 ${170 - plantHeight}`} 
                            stroke={isCompleted ? "#1E8449" : "#27AE60"} 
                            strokeWidth={Math.max(2, growth / 20)} 
                            fill="none" 
                            strokeLinecap="round"
                            className="transition-all duration-1000 ease-out"
                        />

                        {/* Leaves */}
                        {renderLeaves()}

                        {/* Flower (Only if completed or > 95%) */}
                        {(isCompleted || growth >= 95) && (
                            <g transform={`translate(100, ${170 - plantHeight})`} className="animate-bounce-slow">
                                <circle cx="0" cy="0" r="8" fill="#F1C40F" />
                                {[0, 45, 90, 135, 180, 225, 270, 315].map((deg, i) => (
                                    <ellipse 
                                        key={i}
                                        cx="0" 
                                        cy="-12" 
                                        rx="6" 
                                        ry="10" 
                                        fill={seed % 2 === 0 ? "#E74C3C" : "#9B59B6"} // Random flower color Red or Purple
                                        transform={`rotate(${deg})`} 
                                    />
                                ))}
                            </g>
                        )}

                         {/* Bud (If approaching goal) */}
                         {!isCompleted && growth > 70 && growth < 95 && (
                            <circle cx="100" cy={170 - plantHeight} r="6" fill="#2ECC71" stroke="#1E8449" />
                        )}
                    </>
                )}

                {/* Empty State / Soil */}
                {growth === 0 && (
                    <circle cx="100" cy="170" r="3" fill="#5D4037" />
                )}
            </svg>

            {/* Progress Badge Overlay */}
            <div className="absolute bottom-2 right-2 bg-white/80 backdrop-blur-sm px-2 py-1 rounded-lg text-xs font-bold text-primary-navy shadow-sm border border-gray-100">
                {type === 'infinite' ? 'Kebun ' + Math.floor(growth/10) : Math.floor(growth) + '%'}
            </div>
        </div>
    );
};

// --- ULTRA REALISTIC PET VISUALIZER ---
const PetVisualizer: React.FC<{
    progress: number;
    isCompleted: boolean;
    seed: number;
    type: 'finite' | 'infinite';
}> = ({ progress, isCompleted, seed }) => {

    // 1. Determine Stage
    let stage: 'egg' | 'baby' | 'teen' | 'adult' | 'legendary' = 'egg';
    if (progress >= 100 || isCompleted) stage = 'legendary';
    else if (progress >= 80) stage = 'adult';
    else if (progress >= 50) stage = 'teen';
    else if (progress >= 20) stage = 'baby';

    // 2. Procedural Palettes (More refined colors)
    const palettes = [
        { name: 'Phoenix', main: '#e25822', dark: '#8a2b06', light: '#ffab73', eye: '#fbbf24', beak: '#f59e0b' },
        { name: 'Sky', main: '#3b82f6', dark: '#1e3a8a', light: '#93c5fd', eye: '#111827', beak: '#fbbf24' },
        { name: 'Forest', main: '#10b981', dark: '#064e3b', light: '#6ee7b7', eye: '#111827', beak: '#fbbf24' },
        { name: 'Royal', main: '#8b5cf6', dark: '#4c1d95', light: '#c4b5fd', eye: '#1f2937', beak: '#fbbf24' },
        { name: 'Sunshine', main: '#f59e0b', dark: '#b45309', light: '#fcd34d', eye: '#374151', beak: '#f97316' },
    ];
    const p = palettes[seed % palettes.length];

    // 3. Blink State Logic
    const [isBlinking, setIsBlinking] = useState(false);
    useEffect(() => {
        const blinkInterval = setInterval(() => {
            setIsBlinking(true);
            setTimeout(() => setIsBlinking(false), 200); // Blink fast
        }, 3000 + Math.random() * 4000); // Random blink every 3-7 seconds
        return () => clearInterval(blinkInterval);
    }, []);

    // 4. Styles for Animations
    const animStyles = `
        @keyframes breathe {
            0%, 100% { transform: scaleY(1); }
            50% { transform: scaleY(1.03); }
        }
        @keyframes float {
            0%, 100% { transform: translateY(0); }
            50% { transform: translateY(-5px); }
        }
        @keyframes tailSway {
            0%, 100% { transform: rotate(0deg); }
            50% { transform: rotate(5deg); }
        }
        @keyframes leafWave {
            0%, 100% { transform: rotate(0deg); }
            50% { transform: rotate(-10deg); }
        }
    `;

    return (
        <div className="relative w-full h-56 flex items-end justify-center overflow-hidden rounded-t-xl bg-gradient-to-b from-sky-50 to-white group">
            <style>{animStyles}</style>

            {/* Background Atmosphere */}
            <div className="absolute top-0 inset-x-0 h-32 bg-gradient-to-b from-blue-100/50 to-transparent opacity-50"></div>
            {/* Sun/Moon */}
            <div className="absolute top-6 right-8 w-12 h-12 rounded-full bg-yellow-200 blur-xl opacity-60"></div>

            {/* Interactive Hearts on Hover */}
            <div className="absolute top-1/3 left-1/2 -translate-x-1/2 opacity-0 group-hover:opacity-100 transition-opacity duration-700 pointer-events-none z-30">
                <HeartIcon className="w-5 h-5 text-pink-400 animate-bounce absolute -top-8 -right-6" />
                <HeartIcon className="w-4 h-4 text-pink-300 animate-bounce absolute -top-4 -left-6 animation-delay-200" />
            </div>

            <svg width="240" height="220" viewBox="0 0 240 220" className="z-10 filter drop-shadow-xl">
                <defs>
                    <linearGradient id={`bodyGrad-${seed}`} x1="0" y1="0" x2="1" y2="1">
                        <stop offset="0%" stopColor={p.light} />
                        <stop offset="50%" stopColor={p.main} />
                        <stop offset="100%" stopColor={p.dark} />
                    </linearGradient>
                    <radialGradient id="eyeShine" cx="0.3" cy="0.3" r="0.5">
                        <stop offset="0%" stopColor="white" stopOpacity="0.9" />
                        <stop offset="100%" stopColor="white" stopOpacity="0" />
                    </radialGradient>
                    <filter id="softGlow">
                        <feGaussianBlur stdDeviation="2" result="coloredBlur"/>
                        <feMerge>
                            <feMergeNode in="coloredBlur"/>
                            <feMergeNode in="SourceGraphic"/>
                        </feMerge>
                    </filter>
                </defs>

                {/* --- ENVIRONMENT (SARANG / DAHAN) --- */}
                {(stage === 'egg' || stage === 'baby') ? (
                    <g transform="translate(120, 185)">
                        {/* Nest Back */}
                        <path d="M-40,0 Q0,15 40,0" fill="none" stroke="#8B4513" strokeWidth="8" strokeLinecap="round" />
                        <path d="M-35,-5 Q0,10 35,-5" fill="none" stroke="#A0522D" strokeWidth="6" strokeLinecap="round" />

                        {/* The Pet sits here, Nest Front is drawn later for depth */}
                    </g>
                ) : (
                    <g transform="translate(120, 180)">
                        {/* Branch */}
                        <path d="M-120,10 C-60,5 0,15 120,5" stroke="#5D4037" strokeWidth="12" strokeLinecap="round" fill="none" />
                        {/* Leaves */}
                        <g className="origin-bottom animate-[leafWave_3s_ease-in-out_infinite]">
                            <path d="M60,8 Q70,-5 80,8 L70,20 Z" fill="#4ADE80" transform="rotate(-15 60 8)" />
                        </g>
                        <g className="origin-bottom animate-[leafWave_4s_ease-in-out_infinite_reverse]">
                            <path d="M-50,8 Q-60,-5 -70,8 L-60,20 Z" fill="#22C55E" transform="rotate(20 -50 8)" />
                        </g>
                    </g>
                )}

                {/* --- MAIN CREATURE --- */}
                <g 
                    transform={`translate(120, ${stage === 'egg' ? 170 : 155})`} 
                    style={{ animation: stage !== 'egg' ? 'breathe 3s ease-in-out infinite' : 'none' }}
                >

                    {/* --- EGG STAGE --- */}
                    {stage === 'egg' && (
                        <g className="animate-[wiggle_3s_ease-in-out_infinite] origin-bottom">
                            <ellipse cx="0" cy="0" rx="32" ry="40" fill="#FFFBEB" stroke="#E5E7EB" strokeWidth="1" />
                            {/* Spots */}
                            <circle cx="-10" cy="-10" r="4" fill={p.light} opacity="0.5" />
                            <circle cx="15" cy="10" r="6" fill={p.light} opacity="0.5" />
                            <circle cx="5" cy="-25" r="3" fill={p.light} opacity="0.5" />
                            {/* Shading */}
                            <path d="M-25,15 Q0,38 25,15" fill="none" stroke={p.dark} opacity="0.1" strokeWidth="3" />
                            {/* Crack */}
                            {progress > 15 && <path d="M-10,-30 L0,-20 L10,-30" fill="none" stroke="#4B5563" strokeWidth="2" />}
                        </g>
                    )}

                    {/* --- BABY STAGE (CHICK) --- */}
                    {stage === 'baby' && (
                        <g>
                            {/* Fluffy Body */}
                            <circle cx="0" cy="10" r="35" fill={`url(#bodyGrad-${seed})`} />
                            {/* Fluff Details */}
                            <path d="M-35,10 Q-40,0 -32,-5" fill="none" stroke={p.main} strokeWidth="3" strokeLinecap="round" />
                            <path d="M35,10 Q40,0 32,-5" fill="none" stroke={p.main} strokeWidth="3" strokeLinecap="round" />
                            {/* Wings (Tiny) */}
                            <ellipse cx="-20" cy="15" rx="10" ry="6" fill={p.dark} transform="rotate(-20)" />
                            <ellipse cx="20" cy="15" rx="10" ry="6" fill={p.dark} transform="rotate(20)" />
                            {/* Eyes */}
                            <g transform="translate(0, -5)">
                                {isBlinking ? (
                                    <>
                                        <line x1="-18" y1="0" x2="-8" y2="0" stroke="#1F2937" strokeWidth="3" strokeLinecap="round" />
                                        <line x1="8" y1="0" x2="18" y2="0" stroke="#1F2937" strokeWidth="3" strokeLinecap="round" />
                                    </>
                                ) : (
                                    <>
                                        <circle cx="-13" cy="0" r="5" fill="#1F2937" />
                                        <circle cx="-15" cy="-2" r="2" fill="white" opacity="0.8" />
                                        <circle cx="13" cy="0" r="5" fill="#1F2937" />
                                        <circle cx="11" cy="-2" r="2" fill="white" opacity="0.8" />
                                    </>
                                )}
                            </g>
                            {/* Beak */}
                            <path d="M-5,5 L5,5 L0,12 Z" fill={p.beak} stroke={p.dark} strokeWidth="0.5" />
                        </g>
                    )}

                    {/* --- TEEN / ADULT / LEGENDARY STAGE --- */}
                    {(stage === 'teen' || stage === 'adult' || stage === 'legendary') && (
                        <g transform="translate(-10, -10)">
                            {/* Tail Feathers (Behind) */}
                            <g className="origin-top-right animate-[tailSway_4s_ease-in-out_infinite]" style={{ transformOrigin: '20px 40px' }}>
                                <path d="M0,40 C-30,80 -40,100 -20,110 C-10,100 10,80 20,40" fill={p.dark} />
                                {(stage === 'adult' || stage === 'legendary') && (
                                    <path d="M10,40 C-10,90 -20,130 10,140 C30,120 40,90 30,40" fill={p.main} opacity="0.8" />
                                )}
                            </g>

                            {/* Body */}
                            <path 
                                d="M10,20 C-20,20 -30,60 -10,80 C10,95 50,80 55,50 C60,20 30,20 10,20" 
                                fill={`url(#bodyGrad-${seed})`} 
                            />

                            {/* Wing */}
                            <path 
                                d="M15,40 C5,40 0,60 20,70 C40,75 50,60 45,40" 
                                fill={p.dark} 
                                opacity="0.9"
                            />

                            {/* Head Area */}
                            <g transform="translate(45, 30)">
                                {/* Neck/Head Shape */}
                                <circle cx="0" cy="0" r="18" fill={`url(#bodyGrad-${seed})`} />

                                {/* Crest (Hair) */}
                                <path d="M-5,-15 Q5,-30 12,-12" fill={p.light} stroke={p.dark} strokeWidth="0.5" />
                                {stage === 'legendary' && (
                                    <path d="M-8,-15 L0,-35 L8,-15" fill="#FCD34D" filter="url(#softGlow)" />
                                )}

                                {/* Eye */}
                                {isBlinking ? (
                                    <line x1="-2" y1="-2" x2="6" y2="-2" stroke={p.eye} strokeWidth="2" strokeLinecap="round" />
                                ) : (
                                    <g>
                                        <circle cx="2" cy="-2" r="4.5" fill={p.eye} />
                                        <circle cx="3.5" cy="-3.5" r="2" fill="url(#eyeShine)" />
                                    </g>
                                )}

                                {/* Beak */}
                                <path d="M12,-2 Q25,0 12,8" fill={p.beak} />
                            </g>

                            {/* Feet */}
                            <path d="M10,80 L5,95 M30,75 L35,90" stroke="#5D4037" strokeWidth="3" strokeLinecap="round" />
                        </g>
                    )}
                </g>

                {/* --- FOREGROUND NEST (Depth) --- */}
                {(stage === 'egg' || stage === 'baby') && (
                    <g transform="translate(120, 185)">
                        <path d="M-45,0 Q0,20 45,0" fill="none" stroke="#8B4513" strokeWidth="6" strokeLinecap="round" />
                        <path d="M-30,5 Q0,25 30,5" fill="none" stroke="#A0522D" strokeWidth="4" strokeLinecap="round" />
                    </g>
                )}

                {/* --- LEGENDARY PARTICLES --- */}
                {stage === 'legendary' && (
                    <g>
                        <circle cx="60" cy="100" r="2" fill="#FCD34D" className="animate-[float_3s_ease-in-out_infinite]" />
                        <circle cx="180" cy="60" r="3" fill="#FCD34D" className="animate-[float_4s_ease-in-out_infinite]" style={{ animationDelay: '1s' }} />
                        <circle cx="160" cy="140" r="2" fill="#FCD34D" className="animate-[float_5s_ease-in-out_infinite]" style={{ animationDelay: '2s' }} />
                    </g>
                )}

            </svg>

            {/* Stage Badge */}
            <div className="absolute bottom-2 right-2 bg-white/80 backdrop-blur-sm px-3 py-1 rounded-full text-xs font-bold text-primary-navy shadow-sm border border-gray-100 flex items-center gap-1 z-20">
                {stage === 'egg' && 'Telur'}
                {stage === 'baby' && 'Bayi'}
                {stage === 'teen' && 'Remaja'}
                {stage === 'adult' && 'Dewasa'}
                {stage === 'legendary' && <><SparklesIcon className="w-3 h-3 text-yellow-500" /> Legenda</>}
                <span className="ml-1 text-[10px] text-secondary-gray border-l pl-1 border-gray-300">
                    {Math.floor(progress)}%
                </span>
            </div>
        </div>
    );
};

const SavingsGoalCard: React.FC<{
    goal: SavingsGoal;
    onAddSavings: () => void;
    onViewDetails: () => void;
    onOpenGoal: () => void;
}> = ({ goal, onAddSavings, onViewDetails, onOpenGoal }) => {
    // Calculate Visual Progress
    // If Infinite, we set a "Visual Target" (e.g., 5 Million IDR = Full Grown Tree for visualization purposes)
    const visualTarget = goal.isInfinite ? 5000000 : (goal.targetAmount || 1);
    const rawPercentage = (goal.savedAmount / visualTarget) * 100;
    const percentage = Math.min(100, rawPercentage);

    // Default to 'plant' if undefined (backward compatibility)
    const isPet = goal.visualType === 'pet';

    return (
        <div className="bg-white rounded-xl shadow-lg hover:shadow-xl transition-shadow duration-300 overflow-hidden flex flex-col h-full border border-gray-100">
            {/* Visual Area */}
            <div onClick={onAddSavings} className="cursor-pointer group relative">
                 {isPet ? (
                     <PetVisualizer 
                        progress={percentage} 
                        isCompleted={goal.isCompleted} 
                        seed={goal.id} 
                        type={goal.isInfinite ? 'infinite' : 'finite'}
                     />
                 ) : (
                     <PlantVisualizer 
                        progress={percentage} 
                        isCompleted={goal.isCompleted} 
                        seed={goal.id}
                        type={goal.isInfinite ? 'infinite' : 'finite'}
                     />
                 )}

                 {/* Hover overlay to indicate action */}
                 <div className="absolute inset-0 bg-black/0 group-hover:bg-black/5 transition-colors flex items-center justify-center">
                    <div className="opacity-0 group-hover:opacity-100 transform translate-y-4 group-hover:translate-y-0 transition-all duration-300 bg-white/90 px-4 py-2 rounded-full shadow-lg flex items-center gap-2 text-accent-teal font-bold text-sm">
                        <PlusCircleIcon className="w-4 h-4" /> {isPet ? 'Beri Makan' : 'Siram'}
                    </div>
                 </div>
            </div>

            {/* Card Content */}
            <div className="p-4 flex flex-col flex-grow">
                <div className="flex justify-between items-start mb-2">
                    <h3 className="text-lg font-bold text-dark-text truncate w-full" title={goal.name}>{goal.name}</h3>
                </div>

                <div className="mb-4">
                    {goal.isInfinite ? (
                        <div>
                             <p className="text-xs text-secondary-gray uppercase tracking-wider mb-1">Dana Terkumpul</p>
                             <p className="font-bold text-2xl text-primary-navy">{formatCurrency(goal.savedAmount)}</p>
                             <p className="text-[10px] text-gray-400 mt-1">Celengan Fleksibel</p>
                        </div>
                    ) : (
                        <div>
                            <div className="flex justify-between items-end mb-1">
                                <span className="text-2xl font-bold text-primary-navy">{formatCurrency(goal.savedAmount)}</span>
                            </div>
                             <div className="flex justify-between text-xs text-secondary-gray mb-2">
                                <span>Target: {formatCurrency(goal.targetAmount || 0)}</span>
                                <span>{goal.isCompleted ? 'Selesai' : 'Sedang Tumbuh'}</span>
                            </div>
                            <div className="w-full bg-gray-100 rounded-full h-3 overflow-hidden border border-gray-100">
                                <div 
                                    className={`h-full rounded-full transition-all duration-1000 ease-out ${goal.isCompleted ? 'bg-gradient-to-r from-green-400 to-green-600' : 'bg-gradient-to-r from-teal-400 to-teal-600'}`} 
                                    style={{ width: `${percentage}%` }}
                                ></div>
                            </div>
                        </div>
                    )}
                </div>

                {/* Action Area */}
                <div className="mt-auto pt-3 border-t border-gray-50 grid grid-cols-[1fr_auto] gap-3">
                    <button 
                        onClick={onAddSavings} 
                        disabled={goal.isCompleted} 
                        className="w-full bg-primary-navy text-white font-bold py-2.5 px-4 rounded-lg hover:bg-primary-navy-dark transition-colors disabled:bg-gray-300 disabled:cursor-not-allowed shadow-sm text-sm flex items-center justify-center gap-2"
                    >
                        {goal.isCompleted ? <SparklesIcon className="w-4 h-4" /> : <PlusCircleIcon className="w-4 h-4" />}
                        {goal.isCompleted ? 'Tercapai' : (isPet ? 'Tabung (Beri Makan)' : 'Tabung (Siram)')}
                    </button>

                    {goal.isInfinite ? (
                        <button onClick={onOpenGoal} title="Buka Celengan" className="bg-yellow-100 text-yellow-700 font-bold p-2.5 rounded-lg hover:bg-yellow-200 transition-colors">
                            <ArrowUturnLeftIcon className="w-5 h-5" />
                        </button>
                    ) : (
                        <button onClick={onViewDetails} title="Riwayat" className="bg-gray-100 text-secondary-gray font-bold p-2.5 rounded-lg hover:bg-gray-200 hover:text-dark-text transition-colors">
                            <BuildingLibraryIcon className="w-5 h-5" />
                        </button>
                    )}
                </div>
            </div>
        </div>
    );
};

interface SavingsProps {
    state: AppState;
    onOpenAddGoalModal: () => void;
    onOpenAddSavingsModal: (goalId: number) => void;
    onOpenDetailModal: (goalId: number) => void;
    onOpenSavingsGoal: (goalId: number) => void;
}

const Savings: React.FC<SavingsProps> = ({ state, onOpenAddGoalModal, onOpenAddSavingsModal, onOpenDetailModal, onOpenSavingsGoal }) => {
    const { savingsGoals } = state;

    // Total stats for the header
    const totalSaved = useMemo(() => savingsGoals.reduce((acc, g) => acc + g.savedAmount, 0), [savingsGoals]);

    return (
        <main id="savings-page" className="p-4 pb-24 animate-fade-in max-w-3xl mx-auto">
            <div className="flex flex-col md:flex-row justify-between items-center mb-8 gap-4">
                <div>
                    <h1 className="text-3xl font-bold text-primary-navy">Kebun & Kandang Tabungan</h1>
                    <p className="text-secondary-gray text-sm">Rawat tanaman atau peliharaanmu dengan menabung rutin.</p>
                </div>
                <div className="bg-white px-4 py-2 rounded-lg shadow-sm border border-gray-100 flex items-center gap-3">
                    <div className="bg-green-100 p-2 rounded-full">
                        <BuildingLibraryIcon className="w-5 h-5 text-green-600" />
                    </div>
                    <div>
                        <p className="text-xs text-secondary-gray">Total Disimpan</p>
                        <p className="font-bold text-primary-navy">{formatCurrency(totalSaved)}</p>
                    </div>
                </div>
            </div>

            {savingsGoals.length === 0 ? (
                <div className="text-center py-16 bg-white rounded-xl shadow-md border-2 border-dashed border-gray-200 space-y-4">
                    <div className="w-24 h-24 bg-green-50 rounded-full flex items-center justify-center mx-auto mb-4">
                        <BuildingLibraryIcon className="w-10 h-10 text-green-600 opacity-80" />
                    </div>
                    <h3 className="text-xl font-bold text-primary-navy">Belum Ada Koleksi</h3>
                    <p className="text-secondary-gray max-w-xs mx-auto">Mulai tanam benih atau tetaskan telur impianmu sekarang!</p>
                    <button onClick={onOpenAddGoalModal} className="mt-4 bg-accent-teal text-white font-bold py-3 px-6 rounded-full hover:bg-accent-teal-dark transition-all shadow-lg hover:shadow-xl transform hover:-translate-y-1">
                        + Buat Celengan Baru
                    </button>
                </div>
            ) : (
                <div className="space-y-6">
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                        {savingsGoals.map(goal => (
                            <SavingsGoalCard 
                                key={goal.id} 
                                goal={goal}
                                onAddSavings={() => onOpenAddSavingsModal(goal.id)}
                                onViewDetails={() => onOpenDetailModal(goal.id)}
                                onOpenGoal={() => onOpenSavingsGoal(goal.id)}
                            />
                        ))}

                         {/* Add New Card (Visual Placeholder) */}
                        <button 
                            onClick={onOpenAddGoalModal}
                            className="min-h-[320px] rounded-xl border-2 border-dashed border-gray-300 hover:border-accent-teal hover:bg-teal-50 transition-all duration-300 flex flex-col items-center justify-center text-secondary-gray hover:text-accent-teal group"
                        >
                            <div className="w-16 h-16 rounded-full bg-gray-100 group-hover:bg-white flex items-center justify-center mb-3 transition-colors shadow-sm">
                                <PlusCircleIcon className="w-8 h-8" />
                            </div>
                            <span className="font-bold">Tambah Baru</span>
                        </button>
                    </div>
                </div>
            )}
        </main>
    );
};

export default Savings;
